const fecha = $('When Executed by Another Workflow').item.json.fecha;

// ── Solo citas REALES de esa fecha (inmune al timezone) ──────
const items = $input.all().filter(it => {
  const p = it.json && it.json.properties;
  if (!it.json || !it.json.id || !p) return false;
  const start = p['Fecha']?.date?.start || '';
  return String(start).slice(0, 10) === fecha;
});

// ── Separar vehículos y motos ───────────────────────
const vehiculos = [];
const motos     = [];

for (const item of items) {
  const props    = item.json.properties || {};
  const tipo     = props['Vehiculo']?.select?.name?.toLowerCase() || '';
  const servicio = props['Servicio']?.select?.name || '';
  const hora     = props['Hora recepcion ']?.rich_text?.[0]?.plain_text
                || props['Hora recepcion']?.rich_text?.[0]?.plain_text
                || '';

  if (tipo === 'moto') {
    motos.push({ servicio, hora });
  } else {
    vehiculos.push({ servicio, hora });
  }
}

// ── Reglas de capacidad ─────────────────────────
const MAX_VEHICULOS = 2;
const MAX_MOTOS     = 1;
const HORARIO       = '09:00 a 15:00';   // recepción en rango continuo, no slots fijos

// Trabajos de día completo
const tieneFullDayVehiculo = vehiculos.some(v =>
  v.servicio.toLowerCase().includes('completo exterior e interior')
);
const tieneFullDayMoto = motos.some(m =>
  m.servicio.toLowerCase().includes('abrillantado de pintura')
);
// Un trabajo de día completo (moto O vehículo) ocupa TODO el taller ese día.
const diaBloqueado = tieneFullDayVehiculo || tieneFullDayMoto;

// ── Disponibilidad vehículos (tope por conteo, máx 2/día) ──
let cupos_vehiculos = 0;
let mensaje_vehiculos = '';
if (diaBloqueado) {
  mensaje_vehiculos = 'Día reservado por un trabajo de día completo. Sin cupos ese día.';
} else {
  cupos_vehiculos = Math.max(0, MAX_VEHICULOS - vehiculos.length);
  mensaje_vehiculos = cupos_vehiculos === 0
    ? 'Sin cupos disponibles para vehículos ese día.'
    : `Quedan ${cupos_vehiculos} cupo(s) para vehículos ese día. Recepción entre ${HORARIO}.`;
}

// ── Disponibilidad motos (máx 1/día) ───────────────
let mensaje_motos = '';
if (diaBloqueado) {
  mensaje_motos = 'Día reservado por un trabajo de día completo. Sin cupo ese día.';
} else if (motos.length >= MAX_MOTOS) {
  mensaje_motos = 'Sin cupo disponible para motos ese día.';
} else {
  mensaje_motos = `Cupo disponible para motos ese día. Recepción entre ${HORARIO}.`;
}

// ── Resumen de lo ya agendado ────────────────────
const detalle = items.length === 0
  ? 'Ninguna cita agendada ese día.'
  : items.map(i => {
      const p = i.json.properties || {};
      const nombre   = p['Titulo']?.title?.[0]?.plain_text || 'N/A';
      const servicio = p['Servicio']?.select?.name || 'N/A';
      const hora     = p['Hora recepcion ']?.rich_text?.[0]?.plain_text
                    || p['Hora recepcion']?.rich_text?.[0]?.plain_text || 'N/A';
      return `- ${nombre}: ${servicio} a las ${hora}`;
    }).join('\n');

// ── Respuesta final ──────────────────────────
return [{
  json: {
    fecha,
    total_citas:          items.length,
    vehiculos_agendados:  vehiculos.length,
    motos_agendadas:      motos.length,
    cupos_vehiculos,
    horario_recepcion:    HORARIO,
    dia_bloqueado_full_day: diaBloqueado,
    disponibilidad_vehiculos: !diaBloqueado && vehiculos.length < MAX_VEHICULOS,
    disponibilidad_motos:     !diaBloqueado && motos.length < MAX_MOTOS,
    mensaje_vehiculos,
    mensaje_motos,
    detalle_agendado: detalle,
    resumen: `Fecha: ${fecha}. ${mensaje_vehiculos} ${mensaje_motos} Detalle: ${detalle}`
  }
}];
